use strict;
use warnings;

# Skaler degiskenler ($)
my $age = 25;
my $price = 19.99;
my $name = "Ahmet";
my $is_active = 1;  # Perl'de boolean yok, 1/0 kullanilir

print "Isim: $name\n";
print "Yas: $age\n";
print "Fiyat: $price\n";
print "Aktif mi: " . ($is_active ? "evet" : "hayir") . "\n";

# Tip donusumu (Perl otomatik donusturur)
my $age_text = "$age";
my $parsed_age = "30" + 0;
my $parsed_price = "9.5" + 0.0;

print "\nYas metni: $age_text\n";
print "Donusturulen yas: $parsed_age\n";
print "Donusturulen fiyat: $parsed_price\n";

# Sabit (constant)
use constant PI => 3.14159;
print "\nPi sayisi: " . PI . "\n";

# Array (@)
my @colors = ("kirmizi", "mavi", "yesil");
print "\nRenkler: @colors\n";

# Hash (%)
my %person = (name => "Zeynep", age => 28);
print "\nKisi adi: $person{name}\n";
